// WebGPU compat test #2: real buffer round-trip through wgpu —
// createBuffer(COPY_DST|MAP_READ) → queue.writeBuffer → mapAsync(READ) →
// getMappedRange → unmap. Oracle (Deno) and monster must read back the same
// bytes and report the same buffer size.
const out = {};
const adapter = await navigator.gpu.requestAdapter();
const device = await adapter.requestDevice();
const src = new Uint8Array([1, 2, 3, 4, 5, 6, 7, 8]);
const buf = device.createBuffer({
  size: src.byteLength,
  usage: GPUBufferUsage.COPY_DST | GPUBufferUsage.MAP_READ,
});
out.size = buf.size;
device.queue.writeBuffer(buf, 0, src);
await buf.mapAsync(GPUMapMode.READ);
const mapped = new Uint8Array(buf.getMappedRange());
out.bytes = Array.from(mapped);
buf.unmap();
console.log('__RESULT__ ' + JSON.stringify(out));
